<template>
  <view class="empty-content">
    <image class="empty-content-image" :src="setSrc" mode="aspectFit"></image>
  </view>
</template>

<script setup lang="ts">
import { computed } from 'vue';

/**
 * Empty 空状态组件
 * 用于显示列表为空、数据为空等状态
 */

export interface EmptyProps {
  /** 图片类型 */
  src?: string;
}

const props = withDefaults(defineProps<EmptyProps>(), {
  src: 'empty',
});

/** 图片类型映射 */
const typeSrc: Record<string, string> = {
  empty:
    'data:image/png;base64, ',
};

/** 计算属性：根据类型返回对应的图片源 */
const setSrc = computed(() => {
  return typeSrc[props.src] || typeSrc.empty;
});
</script>

<style lang="scss" scoped>
.empty-content {
  display: flex;
  position: fixed;
  inset: 0;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding-bottom: 120upx;
  background: #f8f8f8;

  &-image {
    width: 200upx;
    height: 200upx;
  }
}
</style>
